        /* <flatten type="Javascript"> */
var f = this, id = f.get_id(), n1 = 0, n2 = 0, n3 = 0, v = f._language == 'v', g = f.getItem('d72')._controlBehavior;
var l1 = g._getColumnOrder('stt_rec_dh'), l2 = g._getColumnOrder('stt_rec_tk'), l3 = g._getColumnOrder('stt_rec_pn'), l4 = g._getColumnOrder('stt_rec_ir');
var e1 = (v ? 'Thông tin nhà cung cấp của hóa đơn phải giống với đơn hàng, tờ khai, phiếu nhập mua hoặc phiếu nhập kho.' : 'Invoice should have same supplier information as Purchase Order, Customs Declaration Sheet, Purchase Receipt or Inventory Receipt.');
var e2 = (v ? 'Dữ liệu trong chi tiết không được lấy từ nhiều tờ khai.' : 'Data in grid form should not be extracted from Customs Declaration Sheet.');
var e3 = (v ? 'Dữ liệu trong chi tiết chỉ được lấy số liệu từ đơn hàng, tờ khai, phiếu nhập mua hoặc phiếu nhập kho.' : 'Data in grid form must be extracted from Purchase Order, Customs Declaration Sheet, Purchase Receipt or Inventory Receipt.');

var t = f.getItemValue('ma_kh'), c = '', q = ($func.trim(f.getItemValue('loai_ct')) != '2');
for (var i = 1; i <= g._rowCount; i++) {
  var v1 = (g._getItemValue(i, l1) != ''), v2 = (g._getItemValue(i, l2) != ''), v3 = (g._getItemValue(i, l3) != ''), v4 = (l4 >= 0) && (g._getItemValue(i, l4) != '');
  if ((!v1 || !v2) && !q) v3 = false;
  if (v1 || v2 || v3 || v4) {
    var u = g._getItem(i, 1)._customerIdentity;
    if (!u) u = (f._action == 'Edit') ? f._customerIdentity : t;
    if (t != u) {
      $func.hideWait(id);
      $message.show(e1, String.format('$find(\'{0}\').getItem(\'ma_kh\').focus()', id));
      f._checked = false;
      break;
    }

    if (f._checked) {
      if (v3 && q) {if (n3 == 0) n3 = 1;}
      else {
        if (v2) {if (n2 == 0) n2 = 1;}
        else {
          if (v1) {if (n1 == 0) n1 = 1;}
        }
      }
    }
  }

  if (!c && q && v2) c = g._getItemValue(i, l2);
  if (c && v2) {
    if (c != g._getItemValue(i, l2)) {
      g._errorMultiIssueObject = g._getItem(1, g._getColumnOrder('ma_vt'));
      $message.show(e2, String.format('$find(\'{0}\').focus(\'d72\');$find(\'{1}\')._errorMultiOrderObject.focus()', id, g.get_id()));
      f._checked = false;
      break;
    }
  }
}

if (f._checked) {
  if (n1 + n2 + n3 > 1) {
    f._errorWarningObject = g._getItem(1, g._getColumnOrder('ma_vt'));
    $func.hideWait(id);
    $message.show(e3, String.format('var f = $find(\'{0}\');f.focus(\'d72\');f._errorWarningObject.focus()', id));
    f._checked = false;
  }
}
/* </flatten> */
