script.text:
      &ScriptVoucherInit;
      /* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, 'ong_ba', 'ma_gd', 'loai_ct', 'status');}
/* </flatten> */
function active$Voucher$(f) {&ScriptActiveVoucher;
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  if (f._usedDP) {
    f._gridDP = f.getItem('p&Tag;')._controlBehavior;
    f._gridDP.add_onRender(on$Voucher$GridDownPaymentRender);
  }
  if (f._hideExciseTax) $get('idf_t_ttdb_nt').disabled = true;
  if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');
  &EnvironmentTaxAddRender;
  &VoucherLogHandleStatus;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {&ScriptScatterVoucher;&VoucherLogHandleStatus;if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');}
function close$Voucher$(f) {&ScriptCloseVoucher;
  if (f._usedDP) try {f._gridDP.remove_onRender(on$Voucher$GridDownPaymentRender);} catch (ex) {}
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &EnvironmentTaxRemoveRender;
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d72')._controlBehavior, y = f.getItem('r60')._controlBehavior, z = f.getItem('r30')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      y.setSequenceNumber('line_nbr');
      y.setContinuance('stt_rec0');
      z.setSequenceNumber('line_nbr');
      z.setContinuance('stt_rec0');
      if (f._usedDP) {
        f._gridDP.setSequenceNumber('line_nbr');
        f._gridDP.setContinuance('stt_rec0');
      }
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    case 'Explore':
      &VoucherLogHandleStatusExplore;
      break;
    default:
      break;
  }
}

      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d72')._controlBehavior, y = f.getItem('r60')._controlBehavior, z = f.getItem('r30')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_tien_nt0, t_tien_nt3, t_cp_nt, t_thue_nt, t_ttdb_nt, t_nk_nt, t_tt_nt : t_tien0, t_tien3, t_cp, t_thue, t_ttdb, t_nk, t_tt');
    var u = (f._hideExciseTax ? 'gia_nt0, tien_nt0, gia_nt3, tien_nt3, nk_nt, thue_nt : gia0, tien0, gia3, tien3, nk, thue' : 'gia_nt0, tien_nt0, gia_nt3, tien_nt3, nk_nt, ttdb_nt, thue_nt : gia0, tien0, gia3, tien3, nk, ttdb, thue');
    v.addGridFields(g, u);
    v.addGridFields(y, 'tien_cp_nt : tien_cp');
    v.addGridFields(z, 't_tien_nt,t_thue_nt:t_tien,t_thue');

    &EnvironmentTaxGridFields;
    v.addTotalFields(g, [['t_tien_nt0', 'tien_nt0'], ['t_tien0', 'tien0'], ['t_tien_nt3', 'tien_nt3'], ['t_tien3', 'tien3'], ['t_nk_nt', 'nk_nt'], ['t_nk', 'nk'], ['t_ttdb_nt', 'ttdb_nt'], ['t_ttdb', 'ttdb']]);
    v.addTotalFields(y, [['t_cp_nt', 'tien_cp_nt'], ['t_cp', 'tien_cp']]);
    v.addTotalFields(z, [['t_thue_nt', 't_thue_nt'], ['t_thue', 't_thue']]);

    v.set_referenceFields(null);
    v.set_executeExpression(['[t_tt_nt]:=[t_tien_nt0]+[t_nk_nt]+[t_ttdb_nt]+[t_cp_nt]+[t_thue_nt]', '[t_tt]:=[t_tien0]+[t_nk]+[t_ttdb]+[t_cp]+[t_thue]']);
&CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    var f = sender.get_element().parentForm;
    if (e.object._baseCurrency == e.type) {
      focus$Voucher$Tab(f, true);
      &PostCurrencySelected;
    }
    if (f._usedDP) set$Voucher$GridColumns(f._gridDP);
  }
}



function onChange$Voucher$Tab(sender, e) {focus$Voucher$Tab(sender.parentForm);&PostTabFocus;}
function focus$Voucher$Tab(f, force) {
  var c = 'ma_tt', a = force ? [['d72', c], ['r60', c], ['r30', c]] : ['d72', 'r60', 'r30'];
  if (f._usedDP) Array.add(a, force ? ['p72', c] : 'p72');
  Array.add(a, 'so_ct_goc');
  &ListTabChange;
  &PostTabChange;
  f.focusWhenTabChanged(a);
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {o.parentForm.request('Customer', 'Customer', ['ma_kh'], o);}
function onChange$Voucher$Transaction(o) {o.parentForm.request('Transaction', 'Transaction', ['ma_gd'], o);}
/* </flatten> */
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;

      &VoucherNumberReading;
      &EnvironmentTaxCurrencyResponse;

    case 'Customer':
      f.setItemControlBehavior('tk', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('ma_tt', result[2].Value, result[3].Value, true);
      f.setItemControlBehavior('ong_ba', result[4].Value, null, true);
      f.setItemControlBehavior('dia_chi', result[5].Value, null, true);
      f.setItemControlBehavior('ma_so_thue', result[6].Value, null, true);
      f.setItemControlBehavior('ten_ncc', result[7].Value, null, true);
      f.live(f.getItem('ong_ba'));
      break;
    case 'Transaction':
      f.setItemValue('loai_ct', result[0].Value);
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
    default:
      break;
  }
}
